package com.example.login;

import android.content.Context;
import android.content.SharedPreferences;

public final class CredentialStore {
    private static final String PREFS_NAME = "auth_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_TOKEN = "auth_token";

    private CredentialStore() { }

    private static SharedPreferences prefs(Context context) {
        return context.getApplicationContext().getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }

    public static void save(Context context, String email, String authToken) {
        prefs(context).edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, authToken)
                .apply();
    }

    public static void clear(Context context) {
        prefs(context).edit()
                .remove(KEY_EMAIL)
                .remove(KEY_TOKEN)
                .apply();
    }

    public static boolean hasValidSession(Context context) {
        String email = getEmail(context);
        String token = getAuthToken(context);
        return email != null && !email.isEmpty() && token != null && !token.isEmpty();
    }

    public static String getEmail(Context context) {
        return prefs(context).getString(KEY_EMAIL, null);
    }

    public static String getAuthToken(Context context) {
        return prefs(context).getString(KEY_TOKEN, null);
    }
}

package com.example.login;

import android.os.Handler;
import android.os.Looper;

import java.util.UUID;

public final class AuthService {

    public interface Callback {
        void onSuccess(String email, String authToken);
        void onError(String message);
    }

    private AuthService() { }

    public static void login(String email, String password, Callback callback) {
        new Handler(Looper.getMainLooper()).postDelayed(() -> {
            if (email == null || email.trim().isEmpty()) {
                callback.onError("Email required");
                return;
            }
            if (password == null || password.trim().isEmpty()) {
                callback.onError("Password required");
                return;
            }
            String token = "demo_" + UUID.randomUUID().toString();
            callback.onSuccess(email.trim(), token);
        }, 650);
    }
}

